import{_ as r,c as a,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"隐私条款: 了解数据保护 | OpenCodeDocs","description":"了解 OpenCodeDocs 的隐私政策和数据保护措施。我们如何收集、使用、存储您的个人信息，以及您享有的数据权利。","frontmatter":{"title":"隐私条款: 了解数据保护 | OpenCodeDocs","sidebarTitle":"你的数据去哪了","subtitle":"隐私条款: 了解数据保护","description":"了解 OpenCodeDocs 的隐私政策和数据保护措施。我们如何收集、使用、存储您的个人信息，以及您享有的数据权利。"},"headers":[],"relativePath":"zh/privacy.md","filePath":"zh/privacy.md"}'),t={name:"zh/privacy.md"};function e(n,o,s,g,h,c){return l(),a("div",null,[...o[0]||(o[0]=[i('<h1 id="隐私条款" tabindex="-1">隐私条款 <a class="header-anchor" href="#隐私条款" aria-label="Permalink to &quot;隐私条款&quot;">​</a></h1><p>最后更新日期：2026-01-01</p><p>感谢您使用 OpenCodeDocs。我们非常重视您的隐私和个人信息保护。本隐私条款将帮助您了解我们如何收集、使用、存储和保护您的个人信息。</p><h2 id="_1-我们收集的信息" tabindex="-1">1. 我们收集的信息 <a class="header-anchor" href="#_1-我们收集的信息" aria-label="Permalink to &quot;1. 我们收集的信息&quot;">​</a></h2><p>在您使用 OpenCodeDocs 服务时，我们可能会收集以下类型的信息：</p><h3 id="账号信息" tabindex="-1">账号信息 <a class="header-anchor" href="#账号信息" aria-label="Permalink to &quot;账号信息&quot;">​</a></h3><ul><li><strong>邮箱地址</strong>：用于账号注册、登录验证和重要通知</li><li><strong>用户名</strong>：您选择的显示名称</li><li><strong>GitHub 账号信息</strong>：如您选择使用 GitHub 登录，我们会获取您的公开信息</li></ul><h3 id="使用数据" tabindex="-1">使用数据 <a class="header-anchor" href="#使用数据" aria-label="Permalink to &quot;使用数据&quot;">​</a></h3><ul><li><strong>浏览记录</strong>：您访问的教程页面和时间</li><li><strong>交互行为</strong>：代码复制、章节跳转等操作</li><li><strong>搜索记录</strong>：您在站内的搜索关键词</li></ul><h3 id="设备信息" tabindex="-1">设备信息 <a class="header-anchor" href="#设备信息" aria-label="Permalink to &quot;设备信息&quot;">​</a></h3><ul><li><strong>浏览器类型</strong>：Chrome、Firefox、Safari 等</li><li><strong>操作系统</strong>：Windows、macOS、Linux 等</li><li><strong>IP 地址</strong>：用于安全防护和地区优化</li></ul><h2 id="_2-信息使用方式" tabindex="-1">2. 信息使用方式 <a class="header-anchor" href="#_2-信息使用方式" aria-label="Permalink to &quot;2. 信息使用方式&quot;">​</a></h2><p>我们收集的信息将用于以下目的：</p><ul><li><strong>提供服务</strong>：确保您能够正常访问和使用教程内容</li><li><strong>个性化体验</strong>：记住您的阅读进度和偏好设置</li><li><strong>产品改进</strong>：分析使用模式，优化内容和功能</li><li><strong>安全保障</strong>：检测异常行为，防止滥用</li><li><strong>通知发送</strong>：发送教程更新提醒和重要公告（可选择退订）</li></ul><h2 id="_3-信息共享与披露" tabindex="-1">3. 信息共享与披露 <a class="header-anchor" href="#_3-信息共享与披露" aria-label="Permalink to &quot;3. 信息共享与披露&quot;">​</a></h2><p>我们不会出售您的个人信息。仅在以下情况下可能共享：</p><ul><li><strong>第三方服务提供商</strong>：如 Vercel（托管）、Plausible（分析），他们仅能访问履行职责所需的信息</li><li><strong>法律要求</strong>：依据法律法规或政府要求进行披露</li><li><strong>权益保护</strong>：为保护 OpenCodeDocs 及用户权益的必要情况</li></ul><h2 id="_4-数据存储与安全" tabindex="-1">4. 数据存储与安全 <a class="header-anchor" href="#_4-数据存储与安全" aria-label="Permalink to &quot;4. 数据存储与安全&quot;">​</a></h2><ul><li><strong>存储位置</strong>：数据存储在位于美国和亚太地区的安全服务器</li><li><strong>加密措施</strong>：传输数据使用 TLS/SSL 加密，敏感数据使用 AES-256 加密存储</li><li><strong>访问控制</strong>：严格限制内部人员对数据的访问权限</li><li><strong>保留期限</strong>：账号注销后，个人数据将在 30 天内删除</li></ul><h2 id="_5-您的权利" tabindex="-1">5. 您的权利 <a class="header-anchor" href="#_5-您的权利" aria-label="Permalink to &quot;5. 您的权利&quot;">​</a></h2><p>根据《个人信息保护法》及 GDPR，您享有以下权利：</p><ul><li><strong>访问权</strong>：您有权查看我们持有的关于您的个人信息</li><li><strong>更正权</strong>：您有权要求更正不准确的个人信息</li><li><strong>删除权</strong>：您有权要求删除您的个人信息</li><li><strong>导出权</strong>：您有权以通用格式导出您的数据</li><li><strong>撤回同意</strong>：您有权随时撤回之前给予的同意</li></ul><p>如需行使上述权利，请通过下方联系方式与我们联系。</p><h2 id="_6-cookie-政策" tabindex="-1">6. Cookie 政策 <a class="header-anchor" href="#_6-cookie-政策" aria-label="Permalink to &quot;6. Cookie 政策&quot;">​</a></h2><p>我们使用以下类型的 Cookie：</p><ul><li><strong>必要 Cookie</strong>：保持登录状态、记住语言偏好</li><li><strong>分析 Cookie</strong>：统计访问量和使用模式（使用隐私友好的 Plausible）</li><li><strong>广告 Cookie</strong>： <ul><li>第三方供应商（包括 Google）使用 Cookie 来根据用户在您的网站或其他网站上的过往访问记录投放广告。</li><li>Google 使用广告 Cookie，使其及其合作伙伴能够根据用户对您网站和/或互联网上其他网站的访问记录向用户投放广告。</li><li>用户可以访问 <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Google 广告设置</a> 停用个性化广告。或者，您可以引导用户访问 <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a> 停用第三方供应商用于个性化广告的 Cookie。</li></ul></li></ul><p>您可以通过浏览器设置管理 Cookie。禁用必要 Cookie 可能影响部分功能的正常使用。</p><h2 id="_7-联系我们" tabindex="-1">7. 联系我们 <a class="header-anchor" href="#_7-联系我们" aria-label="Permalink to &quot;7. 联系我们&quot;">​</a></h2><p>如您对本隐私条款有任何疑问，或需要行使您的数据权利，请联系：</p><ul><li><strong>邮箱</strong>：<a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>响应时间</strong>：我们会在 15 个工作日内回复您的请求</li></ul>',30)])])}const p=r(t,[["render",e]]);export{u as __pageData,p as default};
